+            pos += len;
+        }
+    }
+
+    const quote = "\"";
+    @memcpy(buf[pos..][0..quote.len], quote);
+    pos += quote.len;
+
+    // Add line number
+    const line_str = ", line ";
+    @memcpy(buf[pos..][0..line_str.len], line_str);
+    pos += line_str.len;
